import React, { createContext, useContext, useState } from 'react';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [usuario, setUsuario] = useState(() => {
    try {
      const raw = localStorage.getItem('rednorte_usuario');
      if (!raw) return null;
      const u = JSON.parse(raw);
      // Devolver solo campos planos para evitar referencia circular
      return {
        id: u.id,
        mail: u.mail,
        estado: u.estado,
        fechaRegistro: u.fechaRegistro,
        rol: u.rol ? { id: u.rol.id, tag: u.rol.tag, nombre: u.rol.nombre } : null,
        persona: u.persona ? {
          id: u.persona.id,
          apellido1: u.persona.apellido1,
          apellido2: u.persona.apellido2,
          rut: u.persona.rut,
          fechaNacimiento: u.persona.fechaNacimiento,
          sexo: u.persona.sexo,
        } : null,
      };
    } catch { return null; }
  });

  const iniciarSesion = (u) => {
    // Guardar solo datos planos, sin referencias circulares
    const limpio = {
      id: u.id,
      mail: u.mail,
      estado: u.estado,
      fechaRegistro: u.fechaRegistro,
      rol: u.rol ? { id: u.rol.id, tag: u.rol.tag, nombre: u.rol.nombre } : null,
      persona: u.persona ? {
        id: u.persona.id,
        apellido1: u.persona.apellido1,
        apellido2: u.persona.apellido2,
        rut: u.persona.rut,
        fechaNacimiento: u.persona.fechaNacimiento,
        sexo: u.persona.sexo,
      } : null,
    };
    setUsuario(limpio);
    localStorage.setItem('rednorte_usuario', JSON.stringify(limpio));
  };

  const cerrarSesion = () => {
    setUsuario(null);
    localStorage.removeItem('rednorte_usuario');
  };

  const esAdmin = usuario?.rol?.tag === 'ADMIN';

  return (
    <AuthContext.Provider value={{ usuario, iniciarSesion, cerrarSesion, esAdmin }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() { return useContext(AuthContext); }
